%[text] # 例6.4（DCTの基底画像）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_04"; % mfilename

%imgname = "msipimg01";
%imgname = "msipimg07";
%imgfmt = "tiff";
%%
%[text] ## DCT基底ベクトル
M = 4;
C = dctmtx(M);
figure(1) %[output:38063e69]
for idx = 1:M
    b = C(idx,:);
    subplot(M/2,2,idx) %[output:38063e69]
    stem(0:M-1,b,'k','fill')
    axis([0-.5 M-1+.5 -sqrt(2/M) sqrt(2/M)])
    xlabel('$n$','Interpreter','latex')
    %ylabel("${b}_"+num2str(idx-1)+"[n]$",'Interpreter','latex')
    title("$\mathbf{b}_"+num2str(idx-1)+"$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 12;
end
f = gcf;
exportgraphics(f,fullfile(resfolder,"fig06-02a.png")) %[output:38063e69]
%%
%[text] ## DCT基底画像
basisimgs = cell(M,M);
for iRow = 1:M
    for iCol = 1:M
        b1 = C(iCol,:).';
        b2 = C(iRow,:);
        basisimgs{iRow,iCol} = kron(b1,b2)+.5;
    end
end

figure(2) %[output:7811a3f6]
I = montage(basisimgs,'BorderSize',[2 2],'BackgroundColor','white','ThumbnailInterpolation','nearest','ThumbnailSize',[22 22]) %[output:7811a3f6] %[output:9c9fa84d]
imwrite(I.CData,fullfile(resfolder,"fig06-02b.png"))


